  buildStageRuntime(){const cfg=BATTLE_CONFIG.stage?.applyStageDefinition||{};const def=this.stage?.definition;const meta=def?.meta||{};const summary=def?.summary||{};const fallbackMaxEnemyCount=BATTLE_CONFIG.tuning?.maxAliveActorsPerSide??15;const stageMaxEnemyCount=cfg.enabled&&cfg.applyMaxEnemyCount&&Number.isFinite(meta.maxEnemyCount)&&meta.maxEnemyCount>0?meta.maxEnemyCount:fallbackMaxEnemyCount;return{ok:!!def?.ok,source:cfg.runtimeSource||'stage-definition-runtime-flags-v089',stageLen:Number.isFinite(def?.stageLen)?def.stageLen:(Number.isFinite(meta.stageLen)?meta.stageLen:null),enemyBaseHp:Number.isFinite(def?.enemyBaseHp)?def.enemyBaseHp:(Number.isFinite(meta.enemyBaseHp)?meta.enemyBaseHp:null),bgId:Number.isFinite(def?.bgId)?def.bgId:(Number.isFinite(meta.bgId)?meta.bgId:null),maxEnemyCount:Number.isFinite(def?.maxEnemyCount)?def.maxEnemyCount:null,effectiveMaxEnemyCount:stageMaxEnemyCount,effectiveMaxEnemyCountSource:stageMaxEnemyCount===fallbackMaxEnemyCount?'config.tuning.maxAliveActorsPerSide':'stage.meta.maxEnemyCount',applyBaseHp:!!cfg.applyBaseHp,applyMaxEnemyCount:!!cfg.applyMaxEnemyCount,applyBackgroundId:!!cfg.applyBackgroundId,replaceEnemySpawnSchedule:!!cfg.replaceEnemySpawnSchedule,applyStageLenToCoordinate:!!cfg.applyStageLenToCoordinate,enemyBaseWorldX:def?.runtime?.enemyBaseWorldX||800,playerBaseWorldX:def?.runtime?.playerBaseWorldX||3200,enemySpawnWorldX:def?.runtime?.enemySpawnWorldX??700,playerSpawnWorldX:def?.runtime?.playerSpawnWorldX??((Number.isFinite(meta.stageLen)?meta.stageLen:4000)-700),castleId:def?.castleId??def?.runtime?.castleId??def?.castle?.mainCastleId??null,animBaseId:def?.animBaseId??def?.castleId??null,cannonId:def?.runtime?.cannonId??def?.castle?.cannonId??null,castleIdSource:def?.runtime?.castleIdSource||'unknown',castleRawRow:def?.runtime?.castleRawRow||def?.castle?.raw||[],enemyRows:def?.runtime?.enemyRows||[],summary};}

